        try {
            // Writing the HTML content to a file
            FileWriter fileWriter = new FileWriter("output.html");
            fileWriter.write(htmlContent);
            fileWriter.close();

            System.out.println("HTML content has been written to output.html");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

